import{_ as a,c as s,a1 as t,o as p}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Tìm hiểu những Điều Cơ bản về Quét Mạng sử dụng Nmap","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/4-Nmap.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/4-Nmap.md"}'),c={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/4-Nmap.md"};function i(e,n,l,h,o,r){return p(),s("div",null,n[0]||(n[0]=[t(`<h1 id="tim-hieu-nhung-đieu-co-ban-ve-quet-mang-su-dung-nmap" tabindex="-1">Tìm hiểu những Điều Cơ bản về Quét Mạng sử dụng Nmap <a class="header-anchor" href="#tim-hieu-nhung-đieu-co-ban-ve-quet-mang-su-dung-nmap" aria-label="Permalink to &quot;Tìm hiểu những Điều Cơ bản về Quét Mạng sử dụng Nmap&quot;">​</a></h1><p><img src="https://miro.medium.com/max/1500/1*SGiVLHyikvLQEXVkt_Tg5w.jpeg" alt="grid"> Nmap (Zenmap là giao diện đồ họa chính thức của Nmap) là một tiện ích miễn phí, mã nguồn mở (giấy phép) dùng để khám phá mạng và kiểm toán bảo mật.</p><p>Nmap là tiện ích quét mạng phổ biến nhất, mà hầu hết các chuyên gia bảo mật sử dụng trong quá trình đánh giá bảo mật. Nó hỗ trợ nhiều loại kỹ thuật quét mạng khác nhau. Trong quá trình đánh giá bảo mật, bạn sẽ được yêu cầu thực hiện quét mạng bằng Nmap. Do đó, với tư cách là một hacker đạo đức chuyên nghiệp hoặc chuyên gia kiểm thử xâm nhập, bạn sẽ cần quen thuộc với Nmap để thực hiện quét mạng.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Quét toàn bộ mạng con (Subnet).</li><li>Theo dõi tất cả các gói tin gửi và nhận.</li><li>Thực hiện quét toàn diện chậm.</li><li>Tạo một profile mới để thực hiện Null Scan.</li><li>Quét các cổng TCP và UDP.</li><li>Phân tích chi tiết máy chủ và cấu trúc liên kết của chúng.</li><li>Các kỹ thuật quét: <ul><li>TCP Connect Scan</li><li>Xmas Scan</li><li>ACK Flag Scan</li><li>UDP Scan</li><li>IDLE Scan</li></ul></li><li>Tránh phát hiện quét</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy Windows Server 2012.</li><li>Máy Windows 10.</li><li>Máy Ubuntu <a href="https://information.rapid7.com/download-metasploitable-2017.html" target="_blank" rel="noreferrer">Metasploitable</a>.</li><li>Máy Kali Linux.</li><li>Đảm bảo <a href="https://www.techrepublic.com/article/how-to-create-multiple-nat-networks-in-virtualbox/" target="_blank" rel="noreferrer">cấu hình</a> đúng cấu trúc liên kết mạng trên môi trường ảo của bạn.</li></ul><p><strong>Lưu ý</strong> #0: Vì bài lab này chỉ dành riêng cho việc quét mạng, bạn không cần tải xuống các máy cụ thể này. miễn là bạn có bất kỳ máy ảo nào để quét (ngoài Kali), bạn có thể bắt đầu.</p><p><strong>Lưu ý</strong> #1: Bạn có thể sử dụng bất kỳ phiên bản Nmap nào bạn thích. Cá nhân tôi thích phiên bản CLI hơn GUI, nó linh hoạt hơn với quy trình làm việc và có đường cong học tập vững chắc hơn.</p><h2 id="quet-toan-bo-mang-con" tabindex="-1">Quét toàn bộ mạng con <a class="header-anchor" href="#quet-toan-bo-mang-con" aria-label="Permalink to &quot;Quét toàn bộ mạng con&quot;">​</a></h2><p>Mở cửa sổ Terminal và gõ <code>nmap -h</code> để liệt kê tất cả các lệnh có sẵn. Vì Nmap có rất nhiều tùy chọn, bạn có thể sử dụng <a href="https://nmapcookbook.blogspot.com/2010/02/nmap-cheat-sheet.html" target="_blank" rel="noreferrer">cheat sheet</a> này, <a href="https://www.stationx.net/nmap-cheat-sheet/" target="_blank" rel="noreferrer">[2]</a> để xem một số ví dụ.</p><p><code>nmap -O &lt;phạm vi IP&gt;</code></p><p>Tùy chọn <code>-O</code> liên quan đến việc phát hiện hệ điều hành.</p><p>Để chỉ định phạm vi IP, bạn có thể sử dụng hai phương pháp:</p><p><strong>Wildcard</strong>: <code>nmap -O 10.0.2.*</code></p><p><strong>Dấu phân cách mạng con:</strong><code>nmap -O 10.0.2.1/24</code></p><p>Cả hai đều thực hiện tương tự nhau, với một số khác biệt nhỏ, như dấu phân cách mạng con nhanh hơn một chút so với wildcard.</p><p><strong>Chạy quét này và kiểm tra kết quả.</strong></p><p>Nmap quét toàn bộ mạng và hiển thị thông tin cho tất cả các máy chủ, cùng với các cổng mở, loại thiết bị, chi tiết hệ điều hành, v.v.</p><h2 id="theo-doi-tat-ca-cac-goi-tin-gui-va-nhan" tabindex="-1">Theo dõi tất cả các Gói tin Gửi và Nhận <a class="header-anchor" href="#theo-doi-tat-ca-cac-goi-tin-gui-va-nhan" aria-label="Permalink to &quot;Theo dõi tất cả các Gói tin Gửi và Nhận&quot;">​</a></h2><p><strong>Chọn</strong> một máy chủ bạn đã quét</p><p><code>nmap --packet-trace 10.0.2.23</code></p><p>Bằng cách thực thi lệnh <code>--packet-trace</code>, Nmap gửi một số gói tin đến máy dự kiến và nhận các gói tin phản hồi. Nó in tóm tắt mọi gói tin nó gửi và nhận.</p><p>Đầu ra bên dưới cho thấy các gói tin <strong>gửi từ máy chủ đến mục tiêu</strong> và các gói tin <strong>nhận từ mục tiêu về máy chủ</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>SENT (4.1431s) TCP 10.0.2.15:35962 &gt; 10.0.2.23:3005 S ttl=43 id=22968 iplen=44  seq=1965204224 win=1024 &lt;mss 1460&gt;</span></span>
<span class="line"><span>SENT (4.1433s) TCP 10.0.2.15:35962 &gt; 10.0.2.23:4000 S ttl=39 id=51710 iplen=44  seq=1965204224 win=1024 &lt;mss 1460&gt;</span></span>
<span class="line"><span>SENT (4.1434s) TCP 10.0.2.15:35962 &gt; 10.0.2.23:1503 S ttl=53 id=146 iplen=44  seq=1965204224 win=1024 &lt;mss 1460&gt;</span></span>
<span class="line"><span>SENT (4.1435s) TCP 10.0.2.15:35962 &gt; 10.0.2.23:1761 S ttl=56 id=27951 iplen=44  seq=1965204224 win=1024 &lt;mss 1460&gt;</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Lưu ý ở cuối đầu ra cũng hiển thị các cổng TCP mở:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>...</span></span></code></pre></div><h2 id="xac-đinh-dich-vu-voi-tcp-null-scan" tabindex="-1">Xác định Dịch vụ với TCP Null Scan <a class="header-anchor" href="#xac-đinh-dich-vu-voi-tcp-null-scan" aria-label="Permalink to &quot;Xác định Dịch vụ với TCP Null Scan&quot;">​</a></h2><p><code>nmap -sN -T4 -A &lt;địa chỉ IP mục tiêu&gt;</code></p><p><code>-sN</code>: TCP Null Scan. <code>-T4</code>: Timing: (4) Chế độ Aggressive tăng tốc quét bằng cách giả định rằng bạn đang trên mạng đủ nhanh và đáng tin cậy. <code>-A</code>: Bật phát hiện hệ điều hành, phát hiện phiên bản, quét script và traceroute</p><p>Bằng cách thực thi lệnh này, Nmap gửi các gói tin TCP mà không có cờ TCP nào được thiết lập trong gói tin. Nếu quét trả về gói tin RST, điều đó có nghĩa là cổng đã đóng; Nếu không có gì trả về, cổng hoặc là bị lọc hoặc là mở.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>53/tcp   open  domain      ISC BIND 9.4.2</span></span>
<span class="line"><span>| dns-nsid: </span></span>
<span class="line"><span>|_  bind.version: 9.4.2</span></span>
<span class="line"><span>80/tcp   open  http        Apache httpd 2.2.8 ((Ubuntu) DAV/2)</span></span>
<span class="line"><span>|_http-server-header: Apache/2.2.8 (Ubuntu) DAV/2</span></span>
<span class="line"><span>|_http-title: Metasploitable2 - Linux</span></span>
<span class="line"><span>111/tcp  open  rpcbind     2 (RPC #100000)</span></span>
<span class="line"><span>139/tcp  open  netbios-ssn Samba smbd 3.X - 4.X (workgroup: WORKGROUP)</span></span>
<span class="line"><span>445/tcp  open  netbios-ssn Samba smbd 3.X - 4.X (workgroup: WORKGROUP)</span></span>
<span class="line"><span>512/tcp  open  exec        netkit-rsh rexecd</span></span>
<span class="line"><span>513/tcp  open  login       OpenBSD or Solaris rlogind</span></span>
<span class="line"><span>514/tcp  open  tcpwrapped</span></span>
<span class="line"><span>1099/tcp open  java-rmi    GNU Classpath grmiregistry</span></span>
<span class="line"><span>1524/tcp open  bindshell   Metasploitable root shell</span></span>
<span class="line"><span>2049/tcp open  nfs         2-4 (RPC #100003)</span></span>
<span class="line"><span>2121/tcp open  ftp         ProFTPD 1.3.1</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Như đã thấy ở trên, chúng ta có thể thấy một phần đầu ra của quét, được thực hiện trên Metasploitable Linux. Sau đó chúng ta có thể kiểm tra các phiên bản và loại dịch vụ đang chạy trên các cổng mở. Loại thông tin này rất có giá trị vì chúng ta có thể tìm kiếm các lỗ hổng, sai sót v.v.</p><h1 id="cac-ky-thuat-quet" tabindex="-1">Các Kỹ thuật Quét <a class="header-anchor" href="#cac-ky-thuat-quet" aria-label="Permalink to &quot;Các Kỹ thuật Quét&quot;">​</a></h1><p>Nmap đi kèm với nhiều script tích hợp có thể được sử dụng trong quá trình quét nhằm tìm các cổng mở và dịch vụ đang chạy trên các cổng.</p><p>Tóm tắt các quét sẽ được thực hiện:</p><ol><li><strong>TCP Connect Scan</strong> sử dụng kết nối TCP bình thường để xác định xem một cổng có sẵn sàng hay không.</li><li><strong>Xmas Scan</strong> liên quan đến việc gửi các phân đoạn TCP với tất cả các cờ được gửi trong tiêu đề gói tin, tạo ra các gói tin bất hợp pháp theo RFC 793.</li><li><strong>ACK Flag Scan</strong> liên quan đến việc gửi gói tin dò ACK với số thứ tự ngẫu nhiên.</li><li><strong>UDP Scan</strong> liên quan đến việc gửi một gói tin UDP chung đến mục tiêu.</li><li><strong>IDLE Scan</strong> liên quan đến việc gửi các gói tin giả mạo đến mục tiêu.</li></ol><h2 id="_1-tcp-connect-scan" tabindex="-1">1. TCP Connect Scan <a class="header-anchor" href="#_1-tcp-connect-scan" aria-label="Permalink to &quot;1. TCP Connect Scan&quot;">​</a></h2><p>Đây là quét cơ bản nhất của TCP scanning. Cuộc gọi hệ thống connect() được cung cấp bởi hệ điều hành của bạn được sử dụng để mở kết nối đến mọi cổng quan tâm trên máy. Nếu cổng đang lắng nghe, connect() sẽ thành công, ngược lại cổng không thể truy cập. Một ưu điểm lớn của kỹ thuật này là bạn không cần bất kỳ quyền đặc biệt nào.</p><p>Thực hiện quét TCP với timing bình thường (<code>-T3</code>):</p><p><code>nmap -sT -T3 -A &lt;địa chỉ IP mục tiêu&gt;</code></p><p><code>-sT</code>: TCP connect port scan (Mặc định không có quyền root).</p><p>Kết quả quét bao gồm tất cả các cổng mở, kết quả nhận dạng hệ điều hành, kết quả nbstat, kết quả smb-os-discovery, phiên bản smb, v.v.</p><h2 id="_2-xmas-scan" tabindex="-1">2. Xmas Scan <a class="header-anchor" href="#_2-xmas-scan" aria-label="Permalink to &quot;2. Xmas Scan&quot;">​</a></h2><p>Xmas Scan gửi một khung TCP đến thiết bị từ xa với các cờ PSH, URG và FIN được thiết lập. FIN scan chỉ hoạt động với hệ điều hành TCP/IP được phát triển theo RFC 793. Phiên bản hiện tại của MS Windows không được hỗ trợ.</p><p><strong>Lưu ý: Quét tiếp theo sẽ trên máy có bật tường lửa (tức là Windows Server 2012).</strong></p><p><code>nmap -sX -T4 &lt;địa chỉ IP mục tiêu&gt;</code></p><p><code>-sX</code>: Thiết lập các cờ FIN, PSH và URG, làm sáng gói tin như cây thông Giáng sinh</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00040s latency).</span></span>
<span class="line"><span>All 1000 scanned ports on 10.0.2.23 are open|filtered</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 21.64 seconds</span></span></code></pre></div><p>Nmap trả về kết quả nêu rằng tất cả các cổng đều <strong>mở/lọc, điều này có nghĩa là tường lửa đã được cấu hình trên máy mục tiêu.</strong></p><p><strong>Tiếp theo, tắt tường lửa trên máy mục tiêu.</strong></p><h2 id="_3-ack-flag-scan" tabindex="-1">3. ACK Flag Scan <a class="header-anchor" href="#_3-ack-flag-scan" aria-label="Permalink to &quot;3. ACK Flag Scan&quot;">​</a></h2><p>ACK scan không bao giờ tìm thấy cổng mở. Nó chỉ cung cấp trạng thái &quot;filtered&quot; hoặc &quot;unfiltered&quot;, vì nó không bao giờ kết nối với ứng dụng để xác nhận trạng thái &quot;open&quot;.</p><p>Quét này khởi tạo quét ACK và hiển thị trạng thái cổng, như hiển thị bên dưới:</p><p><code>nmap -sA -v -T4 &lt;địa chỉ IP mục tiêu&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initiating ARP Ping Scan at 13:18</span></span>
<span class="line"><span>Scanning 10.0.2.23 [1 port]</span></span>
<span class="line"><span>Completed ARP Ping Scan at 13:18, 0.04s elapsed (1 total hosts)</span></span>
<span class="line"><span>Initiating Parallel DNS resolution of 1 host. at 13:18</span></span>
<span class="line"><span>Completed Parallel DNS resolution of 1 host. at 13:18, 0.05s elapsed</span></span>
<span class="line"><span>Initiating ACK Scan at 13:18</span></span>
<span class="line"><span>Scanning 10.0.2.23 [1000 ports]</span></span>
<span class="line"><span>Completed ACK Scan at 13:18, 1.26s elapsed (1000 total ports)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00029s latency).</span></span>
<span class="line"><span>All 1000 scanned ports on 10.0.2.23 are unfiltered</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Read data files from: /usr/bin/../share/nmap</span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 1.51 seconds</span></span>
<span class="line"><span>           Raw packets sent: 1060 (42.388KB) | Rcvd: 1001 (40.028KB)</span></span></code></pre></div><p>Kẻ tấn công gửi gói tin dò ACK với số thứ tự ngẫu nhiên.</p><ul><li>Không có phản hồi có nghĩa là cổng bị lọc.</li><li>Phản hồi unfiltered có nghĩa là cổng đã đóng.</li></ul><h2 id="_4-udp-scan" tabindex="-1">4. UDP Scan <a class="header-anchor" href="#_4-udp-scan" aria-label="Permalink to &quot;4. UDP Scan&quot;">​</a></h2><p>Quét UDP được thực hiện để tìm bất kỳ cổng UDP nào trên máy mục tiêu. Nếu có để xác định trạng thái của chúng (Mở/Đóng).</p><p><code>nmap -sU -T5 &lt;địa chỉ IP mục tiêu&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>Not shown: 986 open|filtered ports</span></span>
<span class="line"><span>PORT      STATE  SERVICE</span></span>
<span class="line"><span>123/udp   open   ntp</span></span>
<span class="line"><span>137/udp   open   netbios-ns</span></span>
<span class="line"><span>389/udp   open   ldap</span></span>
<span class="line"><span>445/udp   closed microsoft-ds</span></span>
<span class="line"><span>688/udp   closed realm-rusd</span></span>
<span class="line"><span>1001/udp  closed unknown</span></span>
<span class="line"><span>1901/udp  closed fjicl-tep-a</span></span>
<span class="line"><span>8001/udp  closed vcom-tunnel</span></span>
<span class="line"><span>16674/udp closed unknown</span></span>
<span class="line"><span>18818/udp closed unknown</span></span>
<span class="line"><span>28973/udp closed unknown</span></span>
<span class="line"><span>30656/udp closed unknown</span></span>
<span class="line"><span>31109/udp closed unknown</span></span>
<span class="line"><span>57172/udp open   unknown</span></span>
<span class="line"><span>...</span></span></code></pre></div><h2 id="_5-idle-scan" tabindex="-1">5. IDLE Scan <a class="header-anchor" href="#_5-idle-scan" aria-label="Permalink to &quot;5. IDLE Scan&quot;">​</a></h2><p>IDLE scan là một phương pháp quét nâng cao thực hiện quét TCP thực sự mù (blind) trên mục tiêu (có nghĩa là không có gói tin nào được gửi đến mục tiêu từ địa chỉ IP thực của bạn). Thay vào đó, một cuộc tấn công kênh bên (side-channel attack) độc đáo khai thác dự đoán được trình tự tạo ID phân mảnh IP trên máy zombie để thu thập thông tin về các cổng mở trên mục tiêu.</p><p>Trong ví dụ này, zombie sẽ là máy Windows Server 2012 và mục tiêu là máy Windows 10 sử dụng số cổng 80 (hoặc bất kỳ cổng nào bạn muốn kiểm tra).</p><p><code>nmap -Pn -p 80 -sI &lt;địa chỉ IP của zombie&gt; &lt;địa chỉ IP mục tiêu&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Idle scan using zombie 10.0.2.37 (10.0.2.37:80); Class: Incremental</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.0069s latency).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT   STATE SERVICE</span></span>
<span class="line"><span>80/tcp open  http</span></span>
<span class="line"><span>MAC Address: 22:44:11:55:66:77 Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 1.08 seconds</span></span></code></pre></div><p>IDLE scan có thể khó hiểu đối với người mới, tôi khuyên bạn nên thử và kiểm tra theo cách riêng. Tôi khuyên bạn nên xem <a href="https://gbhackers.com/idle-zombie-scan-nmap/" target="_blank" rel="noreferrer">liên kết</a> này để biết thêm thông tin.</p><hr><h2 id="ping-sweep" tabindex="-1">Ping Sweep <a class="header-anchor" href="#ping-sweep" aria-label="Permalink to &quot;Ping Sweep&quot;">​</a></h2><p>Ping sweep là một phương pháp có thể thiết lập một loạt các địa chỉ IP ánh xạ đến các máy chủ đang hoạt động.</p><p>Thay vì kiểm tra từng hệ thống riêng lẻ, chúng ta sẽ kiểm tra tất cả các hệ thống đang sống trong mạng bằng cách thực hiện ping sweep.</p><p><code>-sP</code>: Thực hiện quét chỉ Ping</p><p><code>nmap -sP 10.0.2.*</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.1</span></span>
<span class="line"><span>Host is up (0.0011s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.2</span></span>
<span class="line"><span>Host is up (0.00084s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 (QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.3</span></span>
<span class="line"><span>Host is up (0.00097s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.22</span></span>
<span class="line"><span>Host is up (0.00075s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00066s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.37</span></span>
<span class="line"><span>Host is up (0.00051s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.15</span></span>
<span class="line"><span>Host is up.</span></span>
<span class="line"><span>Nmap done: 256 IP addresses (7 hosts up) scanned in 2.29 seconds</span></span></code></pre></div><p>Nmap quét mạng con và hiển thị danh sách các hệ thống đang sống như đã thấy ở trên. Kết quả có thể khác nhau trong môi trường lab của bạn.</p><h1 id="tranh-phat-hien-quet-su-dung-nhieu-đia-chi-ip-gia" tabindex="-1">Tránh Phát hiện Quét sử dụng Nhiều Địa chỉ IP Giả <a class="header-anchor" href="#tranh-phat-hien-quet-su-dung-nhieu-đia-chi-ip-gia" aria-label="Permalink to &quot;Tránh Phát hiện Quét sử dụng Nhiều Địa chỉ IP Giả&quot;">​</a></h1><p>Lệnh Nmap <code>nmap -D RND:10</code> là tùy chọn giả (decoy), cho phép bạn quét sử dụng nhiều địa chỉ IP giả.</p><p>Tường lửa và IDS phát hiện các nỗ lực quét bình thường trên mạng mục tiêu. Tuy nhiên, bạn có thể sử dụng kỹ thuật địa chỉ IP giả để tránh bị phát hiện.</p><p><strong>Trước khi bắt đầu bài lab này, hãy đảm bảo rằng bạn đã bật tường lửa Windows trên máy mục tiêu.</strong></p><h2 id="phan-manh-ip" tabindex="-1">Phân mảnh IP <a class="header-anchor" href="#phan-manh-ip" aria-label="Permalink to &quot;Phân mảnh IP&quot;">​</a></h2><p>Mở một cửa sổ Terminal mới trên Kali và nhập địa chỉ IP mục tiêu (Windows).</p><p><code>nmap -f &lt;địa chỉ IP mục tiêu&gt;</code></p><p><code>-f</code>: Được sử dụng để quét các gói tin phân mảnh nhỏ.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00074s latency).</span></span>
<span class="line"><span>Not shown: 979 filtered ports</span></span>
<span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>445/tcp   open  microsoft-ds</span></span>
<span class="line"><span>464/tcp   open  kpasswd5</span></span>
<span class="line"><span>593/tcp   open  http-rpc-epmap</span></span>
<span class="line"><span>636/tcp   open  ldapssl</span></span>
<span class="line"><span>3268/tcp  open  globalcatLDAP</span></span>
<span class="line"><span>3269/tcp  open  globalcatLDAPssl</span></span>
<span class="line"><span>3389/tcp  open  ms-wbt-server</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Nmap done: 1 IP address (1 host up) scanned in 13.72 seconds</span></span></code></pre></div><p>Khi dịch vụ Windows Firewall được bật, bạn chỉ có thể thấy các cổng mở như hiển thị trong đầu ra ở trên.</p><h2 id="thuc-hien-maximum-transmission-unit" tabindex="-1">Thực hiện Maximum Transmission Unit <a class="header-anchor" href="#thuc-hien-maximum-transmission-unit" aria-label="Permalink to &quot;Thực hiện Maximum Transmission Unit&quot;">​</a></h2><p>Lệnh này được sử dụng để truyền các gói tin nhỏ hơn thay vì gửi một gói tin hoàn chỉnh mỗi lần.</p><p>Quét này rất giống với quét trước nhưng với <strong>Maximum Transmission Unit</strong> (<code>-mtu</code>) và <code>8</code> byte gói tin.</p><p><code>nmap -mtu 8 &lt;địa chỉ IP mục tiêu&gt;</code></p><p>Nếu mọi thứ hoạt động, kết quả sẽ giống hệt với quét trước.</p><h2 id="gia-mao-đia-chi-ip" tabindex="-1">Giả mạo địa chỉ IP <a class="header-anchor" href="#gia-mao-đia-chi-ip" aria-label="Permalink to &quot;Giả mạo địa chỉ IP&quot;">​</a></h2><p>Lệnh này được sử dụng để quét nhiều địa chỉ IP giả. Nmap sẽ gửi nhiều gói tin với các địa chỉ IP khác nhau, cùng với địa chỉ IP kẻ tấn công thực của bạn.</p><p><code>nmap -D RND:10 &lt;địa chỉ IP mục tiêu&gt;</code></p><p>Một lần nữa, đầu ra giống với các đầu ra trước đó nhưng trên góc nhìn của mục tiêu thì rất khác.</p><p>Kiểm tra Nhật ký trên tường lửa Windows Server và phân tích lần quét cuối cùng được thực hiện. Bạn cũng có thể phân tích thông tin này với Wireshark đang bật.</p><p>Cả hai đều hiển thị nhiều địa chỉ IP cùng với địa chỉ IP kẻ tấn công thực của bạn.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/firewallLog-RND.png" alt="firewall"><em>Nhật ký Windows Firewall: Địa chỉ IP Giả</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6c4f716f549aedea473d2701b1f40bb592413e47/wireshark-RND.png" alt="wireshark"><em>Wireshark: Địa chỉ IP Giả</em></p><hr><p><strong>Tóm lại</strong>: Nmap là một công cụ rất mạnh mẽ cho việc quét mạng / đánh giá bảo mật mạng. Về cơ bản là công cụ bắt buộc phải có khi nói đến An ninh Mạng, Hacker Đạo đức hoặc Kiểm thử Xâm nhập.</p><p>Liên kết hữu ích:</p><ul><li><a href="https://nmap.org/docs.html" target="_blank" rel="noreferrer">Tài liệu chính thức</a></li><li><a href="https://hackertarget.com/nmap-cheatsheet-a-quick-reference-guide/" target="_blank" rel="noreferrer">Cheat Sheet với Mẹo Chuyên nghiệp</a></li><li><a href="https://nmapcookbook.blogspot.com/2010/02/nmap-cheat-sheet.html" target="_blank" rel="noreferrer">Cheat Sheet</a></li><li><a href="https://www.stationx.net/nmap-cheat-sheet/" target="_blank" rel="noreferrer">Cheat Sheet 2</a></li><li><a href="https://www.securesolutions.no/zenmap-preset-scans/" target="_blank" rel="noreferrer">Cài đặt trước Zenmap</a></li><li><a href="https://nmap.org/book/firewall-subversion.html" target="_blank" rel="noreferrer">Bỏ qua Quy tắc Tường lửa</a></li></ul>`,103)]))}const d=a(c,[["render",i]]);export{u as __pageData,d as default};
